# Text Generation App — one-shot completion with named inputs
import requests

response = requests.post(
    "https://api.dify.ai/v1/completion-messages",
    headers={"Authorization": "Bearer app-xxxxxxxxxxxx"},
    json={
        "inputs": {
            "language": "Python",
            "topic": "async generators",
        },
        "response_mode": "blocking",
        "user": "dev-workshop",
    },
)
print(response.json()["message"]["answer"])

# Dify supports calling any HTTP endpoint as a built-in tool.
# Define it under Tools → Custom Tools using an OpenAPI 3.0 schema:

openapi_schema = {
    "openapi": "3.0.0",
    "info": {"title": "Weather API", "version": "1.0"},
    "servers": [{"url": "https://api.weather.example.com"}],
    "paths": {
        "/current": {
            "get": {
                "operationId": "getCurrentWeather",
                "summary": "Get current weather for a city",
                "parameters": [
                    {
                        "name": "city",
                        "in": "query",
                        "required": True,
                        "schema": {"type": "string"},
                    }
                ],
                "responses": {"200": {"description": "Current weather data"}},
            }
        }
    },
}

